('old-data-berta2-all-20260501-01', '828017bf', 'fr', 'Berta 2.0', U&'{"id":"828017bf","Nom commercial":"KREOL TOURS REUNION","Raison sociale":"","Motif Hors ligne":"","En ligne":"non","Zone":"sud","Nom de la commune":"Saint-Philippe","Adresse":"24 All\00E9e des Verveines, 97442 Saint-Philippe - sud sauvage","Site web":"https://www.kreol-tours-reunion.com/","Groupe cat\00E9gorie":"Transport","Nom cat\00E9gorie":"Services","Nom sous cat\00E9gorie":"Excursion touristique","Localisations":"Milieu rural","Code postal":"97442","Bureau postal":"Saint-Philippe","Lieux-dits":"sud sauvage","Prestations sur place":"mat\00E9riel pour l''activit\00E9 , mat\00E9riel de plage , visites p\00E9dagogiques , visites guid\00E9es , Cuisine de produits frais locaux , repas originaux et traditionnels , vtc","Prestations \00E0 proximit\00E9":"sentier de randonn\00E9e,commerce alimentaire,point de vue panoramique,sites touristiques,arr\00EAt bus,station service,sentiers de randonn\00E9es,commerces,site - lieu culturel","Mode de paiement":"Virement,site internet,Carte Bancaire","Langues":"fran\00E7ais,cr\00E9ole","Fixe":"","Mobile":"0692 04 90 15","Autre t\00E9l\00E9phone":"","Fax":"","E-Mail":"contact@kreol-tours-reunion.com","Capacit\00E9":"4","Classement":"","Accroche":"KREOL TOURS REUNION \\nExplorez La R\00E9union autrement : visites priv\00E9es avec guide local, sites embl\00E9matiques, secrets bien gard\00E9s et d\00E9lices cr\00E9oles au menu. 100% p\00E9i","Descriptif":"Le d\00E9part et le programme sont modifiables selon le lieu de prise en charge.\\n\\nJourn\00E9e en privatif (589\20AC) : un luxe ind\00E9niable pour visiter l\2019\00EEle\\nVoyagez \00E0 votre rythme ! Vous visiterez en toute tranquillit\00E9 avec un chauffeur-Guide priv\00E9 et un v\00E9hicule rien que pour vous, jusqu\2019\00E0 4 personnes\\n\\nJourn\00E9e en groupe (169\20AC/pers.) : un luxe accessible pour visiter l\2019\00EEle\\nVous partagerez le v\00E9hicule, par exemple avec un autre couple ou une personne avec un enfant, et respecterez les horaires pour les visites.\\n\\n- SUD SAUVAGE| PICNIC \00AB La nature \00E0 l\2019\00E9tat brut \00BB\\nLe Sud Sauvage est connu pour son c\00F4t\00E9 pr\00E9serv\00E9 et authentique avec ses villages cr\00E9oles.\\n\+01F556 D\00E9part \00E0 7h00 (heure et lieu modulables)\\n\+01F334 Au programme :\\n\2022 Grand Anse (Petite-\00CEle)\\n\2022 Cascades de Langevin (Saint-Joseph)\\n\2022 Exploitation bio (Saint-Joseph)\\n\2022 Sentier des p\00EAcheurs (Saint-Philippe)\\n\2022 Route des laves et coul\00E9e de 2007 (Sainte-Rose)\\n\+01F957 Collation incluse\\n\+01F37D\FE0F D\00E9jeuner cr\00E9ole raffin\00E9 en pleine nature\\n\+01F366 Option : visite d''une vanilleraie (en suppl\00E9ment)\\n\+01F553 Retour vers 16h30 (horaire variable selon la circulation et le lieu de d\00E9part)\\n\\n\\n- VOLCAN | PICNIC \00AB La montagne de feu \00BB\\nCulminant \00E0 2632 m\00E8tres d\2019altitude, il offre aux visiteurs un d\00E9paysement assur\00E9 avec ses paysages lunaires.\\n\+01F556 D\00E9part \00E0 7h00 (heure et lieu modulables)\\n\+01F30B Au programme :\\n\2022 Domaine agricole (Plaine des Cafres, Le Tampon)\\n\2022 Nez de B\0153uf et rivi\00E8re des Remparts (Plaine des Cafres)\\n\2022 Crat\00E8re Commerson et Plaine des Sables (Plaine des Cafres)\\n\2022 Pas de Bellecombe Jacob avec vue sur le Piton de la Fournaise (Volcan, Sainte-Rose)\\n\+01F957 Collation incluse\\n\+01F37D\FE0F D\00E9jeuner cr\00E9ole raffin\00E9 en pleine nature\\n\+01F3DB\FE0F Option : visite de la Cit\00E9 du Volcan (en suppl\00E9ment)\\n\+01F5FA\FE0F Alternative : lieux secrets des Hauts ou littoral Sud-Ouest\\n\+01F554 Retour vers 16h30 \2013 17h00 (variable selon la circulation et le lieu de d\00E9part)\\n\\nAccueil possible uniquement pour personnes autonomes:\\nPersonnes autonomes, avec ou sans canne : maximum 2 personnes\\n\\nPersonnes autonomes utilisant un d\00E9ambulateur pliable et l\00E9ger : maximum 2 personnes.\\nPas adapt\00E9 aux fauteuils roulants ni personne pr\00E9sentant un handicap moteur n\00E9cessitant une assistance permanente","Descriptif du plan d''acc\00E8s":"Prise en charge dans la zone OUEST ou SUD. Autres zones sur devis : contact@kreol-tours-reunion.com","Jours et horaires d''ouverture":"Lundi , Mardi , Mercredi , Jeudi , Vendredi , Samedi","Labels":"Qualit\00E9 Tourisme Ile de La R\00E9union","Date de cr\00E9ation - Etablissement":"28/7/2025","Date de fermeture":"","Fournisseur - Nom":"Mr Olivier MAFFRE","Fournisseur - SIRET":"92103264500019","Fournisseur - adresse":"Mr Olivier MAFFRE: 24 All\00E9e des Verveines, 97429 Petite-Ile","Fournisseur - contacts":"contact@kreol-tours-reunion.com / 0692 04 90 15","Fournisseur - date de cr\00E9ation":"","Fournisseur - Code postal":"","Fournisseur - Bureau":"","Fournisseur - Code NAF":"","Fournisseur - Chambre consulaire":"","Fournisseur - Forme juridique":"","Fournisseur - CFE":"","Nb Produits":"","Coordonn\00E9es GPS":"-21.33853458704427, 55.560267167558834","Liste URL moteur":"","Tarif Montant":"","Tarif libell\00E9":"","Num taxe de s\00E9jour":"","Descriptif OTI":"","Accroche OTI":"","Status":"","commentaire":"","Date de derniere modification":"","Colones modifi\00E9es":"","Aire d''adh\00E9sion":"","source_system":"berta_v2_csv_export"}', 'pending', 'true'),
